import React, { useState, useEffect } from "react";
import { Plus, Edit2, Trash2, Save, X, Eye, EyeOff } from "lucide-react";
import "./AdminDashboard.css";

const AdminDashboard = ({ onLogout }) => {
  const API_BASE = "http://localhost:5000/api";
  const [adminPassword, setAdminPassword] = useState("");
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [showPassword, setShowPassword] = useState(false);

  // Tab navigation
  const [activeTab, setActiveTab] = useState("categories");

  // Edit states
  const [editingId, setEditingId] = useState(null);
  const [editData, setEditData] = useState({});

  // Add new states
  const [showAddForm, setShowAddForm] = useState(false);
  const [newItemType, setNewItemType] = useState("");
  const [newItem, setNewItem] = useState({});

  // Fetch data after authentication
  const fetchData = async () => {
    try {
      setLoading(true);
      const response = await fetch(`${API_BASE}/getData`);
      const result = await response.json();
      setData(result);
      setError("");
    } catch (err) {
      setError("Failed to load data: " + err.message);
    } finally {
      setLoading(false);
    }
  };

  // Handle login
  const handleLogin = async (e) => {
    e.preventDefault();
    if (!adminPassword.trim()) {
      setError("Please enter password");
      return;
    }

    try {
      setLoading(true);
      const response = await fetch(`${API_BASE}/updateData`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          password: adminPassword,
          action: "verify", // Just verify without updating
        }),
      });

      if (response.ok) {
        setIsAuthenticated(true);
        setError("");
        await fetchData();
      } else {
        setError("Invalid password");
      }
    } catch (err) {
      setError("Authentication failed: " + err.message);
    } finally {
      setLoading(false);
    }
  };

  // Update data on server - use action-based API
  // If `files` is provided (array of File objects), send FormData so multer on server can save them.
  const updateDataOnServer = async (action, payload = {}, files = null) => {
    try {
      let response;
      if (files && files.length) {
        const fd = new FormData();
        fd.append('password', adminPassword);
        fd.append('action', action);
        // append payload fields (strings or JSON)
        Object.keys(payload || {}).forEach((k) => {
          const val = payload[k];
          if (typeof val === 'string' || typeof val === 'number' || typeof val === 'boolean') {
            fd.append(k, String(val));
          } else {
            fd.append(k, JSON.stringify(val));
          }
        });
        // append files under the `files` field (server uses multer.any())
        for (let i = 0; i < files.length; i++) fd.append('files', files[i]);

        response = await fetch(`${API_BASE}/updateData`, {
          method: 'POST',
          body: fd,
        });
      } else {
        response = await fetch(`${API_BASE}/updateData`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ password: adminPassword, action, ...payload }),
        });
      }

      const result = await response.json().catch(() => ({}));
      if (response.ok) {
        // Refresh data after successful update
        const dataRes = await fetch(`${API_BASE}/getData`);
        const freshData = await dataRes.json();
        setData(freshData);
        setSuccess('Data updated successfully!');
        setEditingId(null);
        setTimeout(() => setSuccess(''), 3000);
        return true;
      } else {
        setError(result.error || 'Failed to update data');
        return false;
      }
    } catch (err) {
      setError('Update failed: ' + err.message);
      return false;
    }
  };

  // Handle edit save
  const handleEditSave = async (type, id) => {
    if (type === "companyInfo") {
      const success = await updateDataOnServer("updateCompanyInfo", {
        companyInfo: JSON.stringify(editData),
      });
      if (success) setEditingId(null);
    } else if (type === "category") {
      const categoryIndex = data.categories.findIndex(c => c.category === id);
      const success = await updateDataOnServer("updateCategory", {
        catIndex: categoryIndex,
        category: JSON.stringify(editData),
      });
      if (success) setEditingId(null);
    } else if (type === "product") {
      const categoryIndex = data.categories.findIndex(c =>
        c.subProducts.some(p => p.name === id)
      );
      const productIndex = data.categories[categoryIndex].subProducts.findIndex(
        p => p.name === id
      );
      // remove file objects from updates before stringifying
      const { newFiles, ...updatesObj } = editData || {};
      const files = newFiles || null;
      const success = await updateDataOnServer(
        "updateProduct",
        { catIndex: categoryIndex, prodIndex: productIndex, updates: updatesObj },
        files
      );
      if (success) setEditingId(null);
    } else if (type === "gallery") {
      const galleryIndex = data.gallery.findIndex(g => g.id === id);
      const { newFiles, ...updates } = editData || {};
      const files = newFiles || null;
      const success = await updateDataOnServer("updateGalleryImage", { index: galleryIndex, image: updates }, files);
      if (success) setEditingId(null);
    } else if (type === "client") {
      const clientIndex = data.clients.findIndex(c => c.id === id);
      const { newFiles, ...updates } = editData || {};
      const files = newFiles || null;
      const success = await updateDataOnServer("updateClient", { index: clientIndex, client: updates }, files);
      if (success) setEditingId(null);
    }
  };

  // Handle delete
  const handleDelete = async (type, id) => {
    if (!window.confirm("Are you sure you want to delete this item?")) return;

    if (type === "category") {
      const categoryIndex = data.categories.findIndex(c => c.category === id);
      await updateDataOnServer("deleteCategory", {
        catIndex: categoryIndex,
      });
    } else if (type === "product") {
      const categoryIndex = data.categories.findIndex(c =>
        c.subProducts.some(p => p.name === id)
      );
      const productIndex = data.categories[categoryIndex].subProducts.findIndex(
        p => p.name === id
      );
      await updateDataOnServer("deleteProduct", {
        catIndex: categoryIndex,
        prodIndex: productIndex,
      });
    } else if (type === "gallery") {
      const galleryIndex = data.gallery.findIndex(g => g.id === id);
      await updateDataOnServer("deleteGalleryImage", {
        index: galleryIndex,
      });
    } else if (type === "client") {
      const clientIndex = data.clients.findIndex(c => c.id === id);
      await updateDataOnServer("deleteClient", {
        index: clientIndex,
      });
    }
  };

  // Handle add new item
  const handleAddNew = async (e) => {
    e.preventDefault();

    if (newItemType === "category") {
      const newCategory = {
        category: newItem.categoryName,
        subProducts: [],
      };
      const files = newItem.categoryFiles || null;
      const success = await updateDataOnServer("addCategory", { category: newCategory }, files);
      if (success) {
        setShowAddForm(false);
        setNewItem({});
        setNewItemType("");
      }
    } else if (newItemType === "product") {
      const categoryIndex = data.categories.findIndex(
        c => c.category === newItem.categorySelect
      );
      const product = {
        name: newItem.productName,
        price: newItem.productPrice,
        description: newItem.productDescription,
      };
      // If files selected, pass them to updateDataOnServer
      const files = newItem.productFiles || null;
      const success = await updateDataOnServer(
        'addProduct',
        { catIndex: categoryIndex, product: product },
        files
      );
      if (success) {
        setShowAddForm(false);
        setNewItem({});
        setNewItemType("");
      }
    } else if (newItemType === "gallery") {
      const files = newItem.galleryFiles || null;
      const success = await updateDataOnServer(
        'addGalleryImage',
        { caption: newItem.galleryTitle, image: newItem.galleryImage },
        files
      );
      if (success) {
        setShowAddForm(false);
        setNewItem({});
        setNewItemType("");
      }
    } else if (newItemType === "client") {
      const files = newItem.clientFiles || null;
      const success = await updateDataOnServer(
        'addClient',
        { client: newItem.clientName, clientImage: newItem.clientImage },
        files
      );
      if (success) {
        setShowAddForm(false);
        setNewItem({});
        setNewItemType("");
      }
    }
  };

  if (!isAuthenticated) {
    return (
      <div className="admin-login">
        <div className="login-card">
          <h1>🔐 Admin Dashboard</h1>
          <form onSubmit={handleLogin}>
            <div className="form-group">
              <label>Admin Password</label>
              <div className="password-input">
                <input
                  type={showPassword ? "text" : "password"}
                  value={adminPassword}
                  onChange={(e) => setAdminPassword(e.target.value)}
                  placeholder="Enter admin password"
                  disabled={loading}
                />
                <button
                  type="button"
                  className="toggle-password"
                  onClick={() => setShowPassword(!showPassword)}
                >
                  {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                </button>
              </div>
            </div>

            {error && <div className="alert alert-error">{error}</div>}

            <button type="submit" className="btn btn-primary" disabled={loading}>
              {loading ? "Authenticating..." : "Login"}
            </button>
          </form>
        </div>
      </div>
    );
  }

  if (loading && !data) {
    return <div className="admin-loading">Loading dashboard...</div>;
  }

  return (
    <div className="admin-dashboard">
      <div className="admin-header">
        <h1>📊 Admin Dashboard</h1>
        <button className="btn btn-secondary" onClick={onLogout}>
          Logout
        </button>
      </div>

      {error && <div className="alert alert-error">{error}</div>}
      {success && <div className="alert alert-success">{success}</div>}

      <div className="admin-tabs">
        <button
          className={`tab ${activeTab === "company" ? "active" : ""}`}
          onClick={() => setActiveTab("company")}
        >
          Company Info
        </button>
        <button
          className={`tab ${activeTab === "categories" ? "active" : ""}`}
          onClick={() => setActiveTab("categories")}
        >
          Categories & Products
        </button>
        <button
          className={`tab ${activeTab === "gallery" ? "active" : ""}`}
          onClick={() => setActiveTab("gallery")}
        >
          Gallery
        </button>
        <button
          className={`tab ${activeTab === "clients" ? "active" : ""}`}
          onClick={() => setActiveTab("clients")}
        >
          Clients
        </button>
      </div>

      <div className="admin-content">
        {/* Company Info Tab */}
        {activeTab === "company" && data?.companyInfo && (
          <div className="section">
            <h2>Company Information</h2>
            {editingId === "company" ? (
              <form className="edit-form">
                <div className="form-group">
                  <label>Name</label>
                  <input
                    type="text"
                    value={editData.name || ""}
                    onChange={(e) =>
                      setEditData({ ...editData, name: e.target.value })
                    }
                  />
                </div>
                <div className="form-group">
                  <label>Description</label>
                  <textarea
                    value={editData.description || ""}
                    onChange={(e) =>
                      setEditData({ ...editData, description: e.target.value })
                    }
                    rows="5"
                  />
                </div>
                <div className="form-buttons">
                  <button
                    type="button"
                    className="btn btn-success"
                    onClick={() => handleEditSave("companyInfo", "company")}
                  >
                    <Save size={18} /> Save
                  </button>
                  <button
                    type="button"
                    className="btn btn-danger"
                    onClick={() => setEditingId(null)}
                  >
                    <X size={18} /> Cancel
                  </button>
                </div>
              </form>
            ) : (
              <div className="info-card">
                <p>
                  <strong>Name:</strong> {data.companyInfo.name}
                </p>
                <p>
                  <strong>Description:</strong> {data.companyInfo.description}
                </p>
                <button
                  className="btn btn-primary"
                  onClick={() => {
                    setEditingId("company");
                    setEditData(data.companyInfo);
                  }}
                >
                  <Edit2 size={18} /> Edit
                </button>
              </div>
            )}
          </div>
        )}

        {/* Categories & Products Tab */}
        {activeTab === "categories" && data?.categories && (
          <div className="section">
            <h2>Categories & Products</h2>
            <button
              className="btn btn-primary"
              onClick={() => {
                setShowAddForm(true);
                setNewItemType("category");
              }}
            >
              <Plus size={18} /> Add Category
            </button>

            {showAddForm && newItemType.includes("category" || "product") && (
              <form className="add-form" onSubmit={handleAddNew}>
                {newItemType === "category" && (
                  <div className="form-group">
                    <label>Category Name</label>
                    <input
                      type="text"
                      placeholder="e.g., Sign Board"
                      value={newItem.categoryName || ""}
                      onChange={(e) =>
                        setNewItem({ ...newItem, categoryName: e.target.value })
                      }
                      required
                    />
                    <div style={{ marginTop: 8 }}>
                      <label>Category Images (optional)</label>
                      <input
                        type="file"
                        accept="image/*"
                        multiple
                        onChange={(e) =>
                          setNewItem({ ...newItem, categoryFiles: Array.from(e.target.files) })
                        }
                      />
                    </div>
                  </div>
                )}

                {newItemType === "product" && (
                  <>
                    <div className="form-group">
                      <label>Category</label>
                      {/* If category is preselected (category-wise add), don't show dropdown */}
                      {!newItem.categorySelect ? (
                        <select
                          value={newItem.categorySelect || ""}
                          onChange={(e) =>
                            setNewItem({ ...newItem, categorySelect: e.target.value })
                          }
                          required
                        >
                          <option value="">Select Category</option>
                          {data.categories.map((cat) => (
                            <option key={cat.category} value={cat.category}>
                              {cat.category}
                            </option>
                          ))}
                        </select>
                      ) : (
                        <input type="text" value={newItem.categorySelect} readOnly />
                      )}
                    </div>
                    <div className="form-group">
                      <label>Product Name</label>
                      <input
                        type="text"
                        placeholder="e.g., Acrylic Sign Board"
                        value={newItem.productName || ""}
                        onChange={(e) =>
                          setNewItem({ ...newItem, productName: e.target.value })
                        }
                        required
                      />
                    </div>
                    <div className="form-group">
                      <label>Price</label>
                      <input
                        type="text"
                        placeholder="e.g., Rs 65 / Inch"
                        value={newItem.productPrice || ""}
                        onChange={(e) =>
                          setNewItem({ ...newItem, productPrice: e.target.value })
                        }
                        required
                      />
                    </div>
                    <div className="form-group">
                      <label>Description</label>
                      <textarea
                        placeholder="Product description"
                        value={newItem.productDescription || ""}
                        onChange={(e) =>
                          setNewItem({
                            ...newItem,
                            productDescription: e.target.value,
                          })
                        }
                        rows="3"
                      />
                    </div>
                    <div className="form-group">
                      <label>Product Images (optional)</label>
                      <input
                        type="file"
                        accept="image/*"
                        multiple
                        onChange={(e) =>
                          setNewItem({ ...newItem, productFiles: Array.from(e.target.files) })
                        }
                      />
                    </div>

                    <div className="form-group">
                      <label>Specs (optional)</label>
                      {(newItem.productSpecs || []).map((s, idx) => (
                        <div key={idx} style={{ display: 'flex', gap: 8, marginBottom: 6 }}>
                          <input
                            type="text"
                            placeholder="Key"
                            value={s.key}
                            onChange={(e) => {
                              const specs = [...(newItem.productSpecs || [])];
                              specs[idx] = { ...specs[idx], key: e.target.value };
                              setNewItem({ ...newItem, productSpecs: specs });
                            }}
                          />
                          <input
                            type="text"
                            placeholder="Value"
                            value={s.value}
                            onChange={(e) => {
                              const specs = [...(newItem.productSpecs || [])];
                              specs[idx] = { ...specs[idx], value: e.target.value };
                              setNewItem({ ...newItem, productSpecs: specs });
                            }}
                          />
                          <button type="button" className="btn btn-danger" onClick={() => {
                            const specs = [...(newItem.productSpecs || [])]; specs.splice(idx,1);
                            setNewItem({ ...newItem, productSpecs: specs });
                          }}>Remove</button>
                        </div>
                      ))}
                      <button type="button" className="btn btn-secondary" onClick={() => {
                        setNewItem({ ...newItem, productSpecs: [...(newItem.productSpecs || []), { key: '', value: '' }] });
                      }}>+ Add Spec</button>
                    </div>
                  </>
                )}

                <div className="form-buttons">
                  <button type="submit" className="btn btn-success">
                    <Save size={18} /> Add
                  </button>
                  <button
                    type="button"
                    className="btn btn-danger"
                    onClick={() => {
                      setShowAddForm(false);
                      setNewItem({});
                      setNewItemType("");
                    }}
                  >
                    <X size={18} /> Cancel
                  </button>
                </div>
              </form>
            )}

            <div className="categories-list">
              {data.categories.map((category) => (
                <div key={category.category} className="category-card">
                  {editingId === category.category ? (
                    <form className="edit-form">
                      <div className="form-group">
                        <label>Category Name</label>
                        <input
                          type="text"
                          value={editData.category || ""}
                          onChange={(e) =>
                            setEditData({ ...editData, category: e.target.value })
                          }
                        />
                      </div>
                      <div className="form-buttons">
                        <button
                          type="button"
                          className="btn btn-success"
                          onClick={() =>
                            handleEditSave("category", category.category)
                          }
                        >
                          <Save size={18} /> Save
                        </button>
                        <button
                          type="button"
                          className="btn btn-danger"
                          onClick={() => setEditingId(null)}
                        >
                          <X size={18} /> Cancel
                        </button>
                      </div>
                    </form>
                  ) : (
                    <>
                      <h3>{category.category}</h3>
                      <div className="products-sublist">
                        {category.subProducts?.map((product) => (
                          <div key={product.name} className="product-item">
                            {editingId === product.name ? (
                              <form className="edit-form">
                                <div className="form-group">
                                  <label>Name</label>
                                  <input
                                    type="text"
                                    value={editData.name || ""}
                                    onChange={(e) =>
                                      setEditData({
                                        ...editData,
                                        name: e.target.value,
                                      })
                                    }
                                  />
                                </div>
                                <div className="form-group">
                                  <label>Price</label>
                                  <input
                                    type="text"
                                    value={editData.price || ""}
                                    onChange={(e) =>
                                      setEditData({
                                        ...editData,
                                        price: e.target.value,
                                      })
                                    }
                                  />
                                </div>
                                <div className="form-group">
                                  <label>Description</label>
                                  <textarea
                                    value={editData.description || ""}
                                    onChange={(e) =>
                                      setEditData({
                                        ...editData,
                                        description: e.target.value,
                                      })
                                    }
                                    rows="2"
                                  />
                                </div>
                                <div className="form-buttons">
                                  <button
                                    type="button"
                                    className="btn btn-success"
                                    onClick={() =>
                                      handleEditSave("product", product.name)
                                    }
                                  >
                                    <Save size={18} /> Save
                                  </button>
                                  <button
                                    type="button"
                                    className="btn btn-danger"
                                    onClick={() => setEditingId(null)}
                                  >
                                    <X size={18} /> Cancel
                                  </button>
                                </div>
                                <div className="form-group">
                                  <label>Upload Additional Images (optional)</label>
                                  <input
                                    type="file"
                                    accept="image/*"
                                    multiple
                                    onChange={(e) =>
                                      setEditData({ ...editData, newFiles: Array.from(e.target.files) })
                                    }
                                  />
                                </div>
                              </form>
                            ) : (
                              <>
                                <div className="product-info">
                                  <p>
                                    <strong>{product.name}</strong>
                                  </p>
                                  <p className="price">{product.price}</p>
                                  <p className="description">
                                    {product.description}
                                  </p>
                                </div>
                                <div className="product-actions">
                                  <button
                                    className="btn btn-small btn-warning"
                                    onClick={() => {
                                      setEditingId(product.name);
                                      setEditData(product);
                                    }}
                                  >
                                    <Edit2 size={16} />
                                  </button>
                                  <button
                                    className="btn btn-small btn-danger"
                                    onClick={() =>
                                      handleDelete("product", product.name)
                                    }
                                  >
                                    <Trash2 size={16} />
                                  </button>
                                </div>
                              </>
                            )}
                          </div>
                        ))}
                      </div>
                      <div style={{ marginTop: 10 }}>
                        <button
                          className="btn btn-primary"
                          onClick={() => {
                            setShowAddForm(true);
                            setNewItemType('product');
                            setNewItem({ categorySelect: category.category });
                          }}
                        >
                          <Plus size={16} /> Add Product
                        </button>
                      </div>
                      <div className="category-actions">
                        <button
                          className="btn btn-warning"
                          onClick={() => {
                            setEditingId(category.category);
                            setEditData(category);
                          }}
                        >
                          <Edit2 size={18} /> Edit
                        </button>
                        <button
                          className="btn btn-danger"
                          onClick={() =>
                            handleDelete("category", category.category)
                          }
                        >
                          <Trash2 size={18} /> Delete
                        </button>
                      </div>
                    </>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Gallery Tab */}
        {activeTab === "gallery" && data?.gallery && (
          <div className="section">
            <h2>Gallery</h2>
            <button
              className="btn btn-primary"
              onClick={() => {
                setShowAddForm(true);
                setNewItemType("gallery");
              }}
            >
              <Plus size={18} /> Add Gallery Item
            </button>

                {showAddForm && newItemType === "gallery" && (
              <form className="add-form" onSubmit={handleAddNew}>
                <div className="form-group">
                  <label>Title</label>
                  <input
                    type="text"
                    placeholder="Gallery item title"
                    value={newItem.galleryTitle || ""}
                    onChange={(e) =>
                      setNewItem({ ...newItem, galleryTitle: e.target.value })
                    }
                    required
                  />
                </div>
                <div className="form-group">
                  <label>Image URL (optional if uploading files)</label>
                  <input
                    type="text"
                    placeholder="e.g., /images/gallery1.jpg"
                    value={newItem.galleryImage || ""}
                    onChange={(e) =>
                      setNewItem({ ...newItem, galleryImage: e.target.value })
                    }
                  />
                </div>
                <div className="form-group">
                  <label>Upload Images</label>
                  <input
                    type="file"
                    accept="image/*"
                    multiple
                    onChange={(e) => setNewItem({ ...newItem, galleryFiles: Array.from(e.target.files) })}
                  />
                </div>
                <div className="form-buttons">
                  <button type="submit" className="btn btn-success">
                    <Save size={18} /> Add
                  </button>
                  <button
                    type="button"
                    className="btn btn-danger"
                    onClick={() => {
                      setShowAddForm(false);
                      setNewItem({});
                      setNewItemType("");
                    }}
                  >
                    <X size={18} /> Cancel
                  </button>
                </div>
              </form>
            )}

            <div className="gallery-list">
              {data.gallery.map((item) => (
                <div key={item.id} className="gallery-item">
                  {editingId === item.id ? (
                    <form className="edit-form">
                      <div className="form-group">
                        <label>Title</label>
                        <input
                          type="text"
                          value={editData.title || ""}
                          onChange={(e) =>
                            setEditData({ ...editData, title: e.target.value })
                          }
                        />
                      </div>
                      <div className="form-group">
                        <label>Image URL</label>
                        <input
                          type="text"
                          value={editData.image || ""}
                          onChange={(e) =>
                            setEditData({ ...editData, image: e.target.value })
                          }
                        />
                      </div>
                          <div className="form-group">
                            <label>Replace / Upload Image</label>
                            <input
                              type="file"
                              accept="image/*"
                              onChange={(e) => setEditData({ ...editData, newFiles: Array.from(e.target.files) })}
                            />
                          </div>
                      <div className="form-buttons">
                        <button
                          type="button"
                          className="btn btn-success"
                          onClick={() => handleEditSave("gallery", item.id)}
                        >
                          <Save size={18} /> Save
                        </button>
                        <button
                          type="button"
                          className="btn btn-danger"
                          onClick={() => setEditingId(null)}
                        >
                          <X size={18} /> Cancel
                        </button>
                      </div>
                    </form>
                  ) : (
                    <>
                      <img
                        src={item.image ? `${API_BASE.replace('/api', '')}${item.image}` : '/images/placeholder.jpg'}
                        alt={item.title}
                        onError={(e) => (e.target.src = '/images/placeholder.jpg')}
                      />
                      <p>{item.title}</p>
                      <div className="item-actions">
                        <button
                          className="btn btn-small btn-warning"
                          onClick={() => {
                            setEditingId(item.id);
                            setEditData(item);
                          }}
                        >
                          <Edit2 size={16} />
                        </button>
                        <button
                          className="btn btn-small btn-danger"
                          onClick={() => handleDelete("gallery", item.id)}
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    </>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Clients Tab */}
        {activeTab === "clients" && data?.clients && (
          <div className="section">
            <h2>Our Clients</h2>
            <button
              className="btn btn-primary"
              onClick={() => {
                setShowAddForm(true);
                setNewItemType("client");
              }}
            >
              <Plus size={18} /> Add Client
            </button>

            {showAddForm && newItemType === "client" && (
              <form className="add-form" onSubmit={handleAddNew}>
                <div className="form-group">
                  <label>Client Name</label>
                  <input
                    type="text"
                    placeholder="Client name"
                    value={newItem.clientName || ""}
                    onChange={(e) =>
                      setNewItem({ ...newItem, clientName: e.target.value })
                    }
                    required
                  />
                </div>
                {/* Clients only require a name when adding via admin */}
                <div className="form-buttons">
                  <button type="submit" className="btn btn-success">
                    <Save size={18} /> Add
                  </button>
                  <button
                    type="button"
                    className="btn btn-danger"
                    onClick={() => {
                      setShowAddForm(false);
                      setNewItem({});
                      setNewItemType("");
                    }}
                  >
                    <X size={18} /> Cancel
                  </button>
                </div>
              </form>
            )}

            <div className="clients-list">
              {data.clients.map((client) => (
                <div key={client.id} className="client-item">
                  {editingId === client.id ? (
                    <form className="edit-form">
                      <div className="form-group">
                        <label>Name</label>
                        <input
                          type="text"
                          value={editData.name || ""}
                          onChange={(e) =>
                            setEditData({ ...editData, name: e.target.value })
                          }
                        />
                      </div>
                      <div className="form-group">
                        <label>Image URL</label>
                        <input
                          type="text"
                          value={editData.image || ""}
                          onChange={(e) =>
                            setEditData({ ...editData, image: e.target.value })
                          }
                        />
                      </div>
                          <div className="form-group">
                            <label>Upload Logo</label>
                            <input
                              type="file"
                              accept="image/*"
                              onChange={(e) => setEditData({ ...editData, newFiles: Array.from(e.target.files) })}
                            />
                          </div>
                      <div className="form-buttons">
                        <button
                          type="button"
                          className="btn btn-success"
                          onClick={() => handleEditSave("client", client.id)}
                        >
                          <Save size={18} /> Save
                        </button>
                        <button
                          type="button"
                          className="btn btn-danger"
                          onClick={() => setEditingId(null)}
                        >
                          <X size={18} /> Cancel
                        </button>
                      </div>
                    </form>
                  ) : (
                    <>
                      <img
                        src={client.image ? `${API_BASE.replace('/api', '')}${client.image}` : '/images/placeholder.jpg'}
                        alt={client.name}
                        onError={(e) => (e.target.src = '/images/placeholder.jpg')}
                      />
                      <p>{client.name}</p>
                      <div className="item-actions">
                        <button
                          className="btn btn-small btn-warning"
                          onClick={() => {
                            setEditingId(client.id);
                            setEditData(client);
                          }}
                        >
                          <Edit2 size={16} />
                        </button>
                        <button
                          className="btn btn-small btn-danger"
                          onClick={() => handleDelete("client", client.id)}
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    </>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;
